1	package com.fortinet.nac.ingestion.util;
2	
3	import lombok.RequiredArgsConstructor;
4	import org.redisson.api.RBucket;
5	import org.redisson.api.RedissonClient;
6	import org.springframework.stereotype.Component;
7	
8	import java.util.concurrent.TimeUnit;
9	
10	/**
11	 * Dedicated to managing Entity-exist cache and TTL operations
12	 */
13	@Component
14	@RequiredArgsConstructor
15	public class EntityCache {
16	
17	    private final RedissonClient redissonClient;
18	
19	    /**
20	     * Write into entity-exist cache
21	     */
22	    public void cacheEntityId(String key, Long entityId, int ttl) {
23	        // RBucket.set() may throw exceptions at least in the following cases:
24	        //   1. Redis is down or the connection pool is exhausted
25	        //   2. Network jitter causing timeouts
26	        //   3. Redis runs out of memory (OOM)
27	        RBucket<String> bucket = redissonClient.getBucket(key);
28	        bucket.set(entityId.toString(), ttl, TimeUnit.SECONDS);
29	    }
30	
31	    /**
32	     * Query entity-exist cache
33	     */
34	    public Long getCachedEntityId(String key) {
35	        try {
36	            RBucket<String> bucket = redissonClient.getBucket(key);
37	            String val = bucket.get();
38	            return (val == null || val.isEmpty()) ? null : Long.parseLong(val);
39	        } catch (NumberFormatException e) {
40	            return null;
41	        }
42	    }
43	}
