    @JsonRawValue
    private String processingResult;  // JSON blob

    @Column(nullable = false)
    private Instant createdAt;

    @Column(nullable = false)
    private Instant updatedAt;

    @Column(nullable = false)
    private boolean interrupted;

    @Column(nullable = false, length = 255)
