    .id(idService.nextId())
    .type(EntityType.valueOf(req.getEntityType()))
    .source(req.getSource())
    .userId(req.getUserId())
    .hostId(req.getHostId())
    .adapterId(req.getAdapterId())
    // ... other fields
    .build();

